import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import '../styles/Auth.css';

const SignInPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      setError('');
      setLoading(true);

      const result = await login(email, password);

      if (result.success) {
        navigate('/dashboard');
      } else {
        setError('Failed to sign in. Please check your credentials.');
      }
    } catch (err) {
      setError('Failed to sign in. Please try again.');
    }

    setLoading(false);
  };

  const handleDemoLogin = async () => {
    try {
      setError('');
      setLoading(true);

      // Use demo credentials
      const result = await login('demo@example.com', 'password123');

      if (result.success) {
        navigate('/dashboard');
      } else {
        // If login fails, try creating the demo user
        const signupResult = await login('demo@example.com', 'password123');
        if (signupResult.success) {
          navigate('/dashboard');
        } else {
          setError('Failed to sign in with demo account');
        }
      }
    } catch (err) {
      setError('Failed to sign in with demo account');
    }

    setLoading(false);
  };

  return (
    <div className="auth-page-container">
      <div className="auth-card">
        <h1 className="auth-title">TaskTrail</h1>
        <h2 className="auth-subtitle">Welcome Back</h2>
        {error && <div className="error-message">{error}</div>}
        <form onSubmit={handleSubmit} className="auth-form">
          <div className="form-group">
            <label htmlFor="email">Email Address</label>
            <input
              type="email"
              id="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
          </div>
          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>
          <button type="submit" className="auth-btn primary" disabled={loading}>
            {loading ? 'Signing In...' : 'Sign In'}
          </button>
          <div className="divider">
            <span>or</span>
          </div>
          <button 
            type="button" 
            className="auth-btn demo"
            onClick={handleDemoLogin}
            disabled={loading}
          >
            {loading ? 'Signing in...' : 'Try Demo Account'}
          </button>
        </form>
        <div className="auth-links">
          <p>Don't have an account? <Link to="/signup">Sign up</Link></p>
        </div>
      </div>
    </div>
  );
};

export default SignInPage;
